"use strict";
import axios from "axios";
const api = axios.create({
  baseURL: "/api",
  timeout: 15e3,
  headers: { "Content-Type": "application/json" }
});
api.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem("token");
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => Promise.reject(error)
);
api.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem("token");
      localStorage.removeItem("user");
      window.location.href = "/auth/login";
    }
    return Promise.reject(error);
  }
);
export const authAPI = {
  login: (data) => api.post("/auth/login", data),
  register: (data) => api.post("/auth/register", data),
  logout: () => api.post("/auth/logout"),
  me: () => api.get("/auth/me")
};
export const postsAPI = {
  getPosts: (filters) => api.get("/forum/posts", { params: filters }),
  getPostById: (id) => api.get(`/forum/posts/${id}`),
  createPost: (data) => api.post("/forum/posts", data),
  updatePost: (id, data) => api.put(`/forum/posts/${id}`, data),
  deletePost: (id) => api.delete(`/forum/posts/${id}`),
  votePost: (id, voteType) => api.post(`/forum/posts/${id}/vote`, { voteType }),
  getUserVote: (postId) => api.get(`/forum/posts/${postId}/my-vote`),
  savePost: (id) => api.post(`/forum/posts/${id}/save`),
  getSavedPosts: () => api.get("/forum/saved-posts")
};
export const commentsAPI = {
  getComments: (postId) => api.get(`/forum/posts/${postId}/comments`),
  createComment: (postId, content) => api.post(`/forum/posts/${postId}/comments`, { content }),
  replyComment: (postId, parentCommentId, content) => api.post(`/forum/posts/${postId}/comments/${parentCommentId}/reply`, { content }),
  deleteComment: (id) => api.delete(`/forum/comments/${id}`),
  voteComment: (id, voteType) => api.post(`/forum/comments/${id}/vote`, { voteType })
};
export const tagsAPI = {
  getTags: () => api.get("/forum/tags")
};
export const notificationsAPI = {
  getNotifications: () => api.get("/notifications"),
  markAsRead: (id) => api.put(`/notifications/${id}/read`),
  markAllAsRead: () => api.put("/notifications/read-all")
};
export const adminStatsAPI = {
  getStats: () => api.get("/admin/stats")
};
export const adminUsersAPI = {
  getUsers: (params) => api.get("/admin/users", { params }),
  getUserById: (id) => api.get(`/admin/users/${id}`),
  createUser: (data) => api.post("/admin/users", data),
  updateUser: (id, data) => api.put(`/admin/users/${id}`, data),
  updateUserStatus: (id, status) => api.patch(`/admin/users/${id}/status`, { status }),
  lockUser: (id) => api.patch(`/admin/users/${id}/lock`),
  resetPassword: (id) => api.post(`/admin/users/${id}/reset-password`),
  deleteUser: (id) => api.delete(`/admin/users/${id}`)
};
export const adminPostsAPI = {
  getPosts: (params) => api.get("/admin/posts", { params }),
  getPostById: (id) => api.get(`/admin/posts/${id}`),
  updatePostStatus: (id, status) => api.patch(`/admin/posts/${id}/status`, { status }),
  deletePost: (id) => api.delete(`/admin/posts/${id}`)
};
export const adminTagsAPI = {
  getTags: () => api.get("/admin/tags"),
  createTag: (data) => api.post("/admin/tags", data),
  updateTag: (id, data) => api.put(`/admin/tags/${id}`, data),
  deleteTag: (id) => api.delete(`/admin/tags/${id}`)
};
export default api;
